    &lt;div class="lt-group"&gt;
      &lt;div class="lt-group-title"&gt;Transformation matrix&lt;/div&gt;
      &lt;div class="lt-row"&gt;
        &lt;label&gt;a&lt;/label&gt;&lt;input class="lt-spin" type="number" step="0.5" value="1" id="lt-a"&gt;
