      &lt;/div&gt;
      &lt;div class="lt-row"&gt;
        &lt;label&gt;c&lt;/label&gt;&lt;input class="lt-spin" type="number" step="0.5" value="0" id="lt-c"&gt;
        &lt;label&gt;d&lt;/label&gt;&lt;input class="lt-spin" type="number" step="0.5" value="1" id="lt-d"&gt;
      &lt;/div&gt;
    &lt;/div&gt;
    &lt;div class="lt-group"&gt;
      &lt;div class="lt-group-title"&gt;Vectors to transform&lt;/div&gt;
      &lt;div class="lt-row"&gt;
        &lt;span style="font-size:12px;color:#888"&gt;v₁&lt;/span&gt;
        &lt;span style="display:inline-flex;flex-direction:column;gap:4px"&gt;
          &lt;input class="lt-spin" type="number" step="0.5" value="1" id="lt-v1x"&gt;
