        &lt;span style="display:inline-flex;flex-direction:column;gap:4px"&gt;
          &lt;input class="lt-spin" type="number" step="0.5" value="0" id="lt-v2x"&gt;
          &lt;input class="lt-spin" type="number" step="0.5" value="1" id="lt-v2y"&gt;
        &lt;/span&gt;
      &lt;/div&gt;
    &lt;/div&gt;
    &lt;div class="lt-group"&gt;
      &lt;div class="lt-group-title"&gt;Result&lt;/div&gt;
