        &lt;span style="font-size:12px;color:#888"&gt;v₁'&lt;/span&gt;
        &lt;span class="lt-result" style="display:inline-flex;flex-direction:column;align-items:center;border:1px solid #ccc;border-radius:4px;padding:2px 6px;line-height:1.4"&gt;
          &lt;span id="lt-r1x"&gt;1&lt;/span&gt;
          &lt;span id="lt-r1y"&gt;0&lt;/span&gt;
        &lt;/span&gt;
        &lt;span style="font-size:12px;color:#888;margin-left:6px"&gt;v₂'&lt;/span&gt;
        &lt;span class="lt-result" style="display:inline-flex;flex-direction:column;align-items:center;border:1px solid #ccc;border-radius:4px;padding:2px 6px;line-height:1.4"&gt;
