matA = { return controlPanel["lt-a"]; }
matB = { return controlPanel["lt-b"]; }
matC = { return controlPanel["lt-c"]; }
matD = { return controlPanel["lt-d"]; }
v1x = { return controlPanel["lt-v1x"]; }
v1y = { return controlPanel["lt-v1y"]; }
v2x = { return controlPanel["lt-v2x"]; }
v2y = { return controlPanel["lt-v2y"]; }


























































presetMat = {
  const name = presetSelect;
  if (name !== "(custom)" && presets.has(name)) {
    return presets.get(name);
  }
  return null;
}

// Parse current matrix
mat = {
  if (presetMat) return presetMat;
  return {
    a: parseFloat(matA) || 0,
    b: parseFloat(matB) || 0,
    c: parseFloat(matC) || 0,
    d: parseFloat(matD) || 0
  };
}

v1 = [parseFloat(v1x) || 0, parseFloat(v1y) || 0]
v2 = [parseFloat(v2x) || 0, parseFloat(v2y) || 0]

transform = (x, y, m) =&gt; [m.a * x + m.b * y, m.c * x + m.d * y]

// Update result display
{
  const [r1x, r1y] = transform(v1[0], v1[1], mat);
  const [r2x, r2y] = transform(v2[0], v2[1], mat);
  const det = mat.a * mat.d - mat.b * mat.c;
  const el = (id) =&gt; document.querySelector(`#${id}`);
  if (el("lt-r1x")) {
    el("lt-r1x").textContent = round4(r1x);
    el("lt-r1y").textContent = round4(r1y);
    el("lt-r2x").textContent = round4(r2x);
    el("lt-r2y").textContent = round4(r2y);
    el("lt-det").textContent = round4(det);
  }
  return html``;
}












































animProgress = {
  animBtn;
  presetSelect;
  let t = 0;
  while (t &lt; 1) {
    yield t;
    await Promises.delay(20);
    t = Math.min(1, t + 0.02 * animSpeed);
  }
  yield 1;
}

currentMat = {
  const t = animProgress;
  return {
    a: 1 + t * (mat.a - 1),
    b: 0 + t * (mat.b - 0),
    c: 0 + t * (mat.c - 0),
    d: 1 + t * (mat.d - 1),
  };
}
















// ── Main visualization ─────────────────────────────────────────────────────────

{
  const W = 420, H = 420;
  const margin = 40;
  const range = 4;

  const sx = (x) =&gt; margin + (x + range) / (2 * range) * (W - 2 * margin);
  const sy = (y) =&gt; H - margin - (y + range) / (2 * range) * (H - 2 * margin);

  const container = d3.create("div")
    .style("display", "flex").style("flex-wrap", "wrap")
    .style("gap", "16px").style("justify-content", "center");

  // Face geometry
  const faceHead = Array.from({length: 60}, (_, i) =&gt; {
    const a = (i / 60) * 2 * Math.PI;
    return [0.8 * Math.cos(a), 0.8 * Math.sin(a)];
  });
  const eyeRadius = 0.08;
  const faceEyes = [[-0.3, 0.3], [0.3, 0.3]].map(([cx, cy]) =&gt;
    Array.from({length: 20}, (_, i) =&gt; {
      const a = (i / 20) * 2 * Math.PI;
      return [cx + eyeRadius * Math.cos(a), cy + eyeRadius * Math.sin(a)];
    })
  );
  const faceMouth = Array.from({length: 21}, (_, i) =&gt; {
    const a = Math.PI + (i / 20) * Math.PI;
    return [0.35 * Math.cos(a), -0.15 + 0.2 * Math.sin(a)];
  });

  function drawPlot(parent, title, m, isT) {
    const svg = parent.append("svg").attr("width", W).attr("height", H)
      .style("border", "1px solid #ddd").style("border-radius", "8px")
      .style("background", "#fafafa");

    // Light grid
    for (let i = -range; i &lt;= range; i++) {
      svg.append("line").attr("x1", sx(i)).attr("y1", sy(-range))
        .attr("x2", sx(i)).attr("y2", sy(range))
        .attr("stroke", "#e0e0e0").attr("stroke-width", 0.5);
      svg.append("line").attr("x1", sx(-range)).attr("y1", sy(i))
        .attr("x2", sx(range)).attr("y2", sy(i))
        .attr("stroke", "#e0e0e0").attr("stroke-width", 0.5);
    }

    // Transformed grid
    if (isT) {
      const g = range + 1;
      for (let i = -g; i &lt;= g; i++) {
        let [x1,y1] = transform(i, -g, m), [x2,y2] = transform(i, g, m);
        svg.append("line").attr("x1",sx(x1)).attr("y1",sy(y1))
          .attr("x2",sx(x2)).attr("y2",sy(y2))
          .attr("stroke","#FFB347").attr("stroke-width",0.8).attr("opacity",0.5);
        [x1,y1] = transform(-g, i, m); [x2,y2] = transform(g, i, m);
        svg.append("line").attr("x1",sx(x1)).attr("y1",sy(y1))
          .attr("x2",sx(x2)).attr("y2",sy(y2))
          .attr("stroke","#FFB347").attr("stroke-width",0.8).attr("opacity",0.5);
      }
    }

    // Axes
    svg.append("line").attr("x1",sx(-range)).attr("y1",sy(0))
      .attr("x2",sx(range)).attr("y2",sy(0)).attr("stroke","black").attr("stroke-width",1.2);
    svg.append("line").attr("x1",sx(0)).attr("y1",sy(-range))
      .attr("x2",sx(0)).attr("y2",sy(range)).attr("stroke","black").attr("stroke-width",1.2);

    // Ticks
    for (let i = -range; i &lt;= range; i++) {
      if (i === 0) continue;
      svg.append("text").attr("x",sx(i)).attr("y",sy(0)+15)
        .attr("text-anchor","middle").attr("font-size",10).attr("fill","#666").text(i);
      svg.append("text").attr("x",sx(0)-12).attr("y",sy(i)+4)
        .attr("text-anchor","middle").attr("font-size",10).attr("fill","#666").text(i);
    }

    // Parallelogram
    const corners = isT
      ? [[0,0], transform(v1[0],v1[1],m),
         transform(v1[0]+v2[0],v1[1]+v2[1],m), transform(v2[0],v2[1],m)]
      : [[0,0], v1, [v1[0]+v2[0],v1[1]+v2[1]], v2];

    const fc = isT ? "#FFB347" : "#87CEEB";
    const ec = isT ? "#CC7000" : "#4682B4";
    svg.append("polygon")
      .attr("points", corners.map(([x,y]) =&gt; `${sx(x)},${sy(y)}`).join(" "))
      .attr("fill",fc).attr("fill-opacity",0.3).attr("stroke",ec).attr("stroke-width",2);
    for (const [x,y] of corners)
      svg.append("circle").attr("cx",sx(x)).attr("cy",sy(y)).attr("r",4).attr("fill",ec);

    // Arrows
    for (const [color, id] of [["#4682B4","b1"],["#CC7000","o1"],["#2E8B57","g1"],["#C71585","p1"]]) {
      svg.append("defs").append("marker").attr("id",`ar-${id}`)
        .attr("viewBox","0 0 10 10").attr("refX",9).attr("refY",5)
        .attr("markerWidth",8).attr("markerHeight",8).attr("orient","auto-start-reverse")
        .append("path").attr("d","M 0 0 L 10 5 L 0 10 z").attr("fill",color);
    }

    function arrow(tx, ty, color, markerId, label) {
      const [px,py] = isT ? transform(tx,ty,m) : [tx,ty];
      svg.append("line").attr("x1",sx(0)).attr("y1",sy(0))
        .attr("x2",sx(px)).attr("y2",sy(py))
        .attr("stroke",color).attr("stroke-width",2.5)
        .attr("marker-end",`url(#ar-${markerId})`);
      svg.append("text").attr("x",sx(px)+8).attr("y",sy(py)-8)
        .attr("font-size",12).attr("fill",color).attr("font-weight","bold").text(label);
    }
    arrow(v1[0],v1[1], isT?"#CC7000":"#4682B4", isT?"o1":"b1", isT?"v₁'":"v₁");
    arrow(v2[0],v2[1], isT?"#C71585":"#2E8B57", isT?"p1":"g1", isT?"v₂'":"v₂");

    // Face
    if (showImageToggle) {
      const tp = (x,y) =&gt; isT ? transform(x,y,m) : [x,y];
      const headPath = faceHead.map(([x,y],i) =&gt; {
        const [px,py] = tp(x,y);
        return `${i===0?'M':'L'} ${sx(px)} ${sy(py)}`;
      }).join(" ") + " Z";
      svg.append("path").attr("d",headPath)
        .attr("fill","none").attr("stroke","#555").attr("stroke-width",2);
      for (const eyePts of faceEyes) {
        const eyePath = eyePts.map(([x,y],i) =&gt; {
          const [px,py] = tp(x,y);
          return `${i===0?'M':'L'} ${sx(px)} ${sy(py)}`;
        }).join(" ") + " Z";
        svg.append("path").attr("d",eyePath).attr("fill","#555").attr("stroke","none");
      }
      const mouthPath = faceMouth.map(([x,y],i) =&gt; {
        const [px,py] = tp(x,y);
        return `${i===0?'M':'L'} ${sx(px)} ${sy(py)}`;
      }).join(" ");
      svg.append("path").attr("d",mouthPath)
        .attr("fill","none").attr("stroke","#555").attr("stroke-width",2);
    }

    svg.append("text").attr("x",W/2).attr("y",20)
      .attr("text-anchor","middle").attr("font-size",14).attr("fill","gray").text(title);
  }

  drawPlot(container, "Original", {a:1,b:0,c:0,d:1}, false);
  drawPlot(container, "Transformed", currentMat, true);

  return container.node();
}






Your task: interact with the tool above to complete the following:

Select a few different options from the drop-down menu. Observe how the right plot changes after the selection. Each time you select a new option, the animation will restart. If the animation is too fast, you can slow it down.
Tick the face box. A face should appear on both plots.

Find a transformation that makes the face look left (but keeps the up-down orientation).
